-- =====================================================
-- 2. Структурированные критерии перехода shoulder_rcr_infraspinatus
--    (JOIN на rehab_phases по program_type+phase_number → реальный phase_id)
-- =====================================================
WITH criteria_data (
  phase_number, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2,
  staleness_days, self_report_question, self_report_hint,
  position, is_required
) AS (VALUES
  -- Фаза 0 → Фаза 1 (подготовка к операции → максимальная защита)
  (0, 'sling_regime_understood', 'Понимаете режим повязки и какие движения после операции запрещены', 'self_report',      NULL::varchar, NULL::varchar, NULL::varchar, NULL::numeric, NULL::numeric, 7::smallint, 'Понимаете режим повязки и какие движения после операции запрещены?', 'Расскажите куратору, как будете носить повязку и чего избегать', 10::smallint, TRUE),
  (0, 'post_op_exercises_learned', 'Освоили упражнения для периода после операции',                  'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Освоили упражнения, которые нужно делать после операции?', 'Покажите их куратору', 20::smallint, TRUE),
  (0, 'sling_demo_pendulum',     'Уверенно надеваете и снимаете повязку, показываете маятниковые покачивания рукой', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),

  -- Фаза 1 → Фаза 2 (максимальная защита → возврат активных движений)
  (1, 'passive_flexion_120_p1',  'Сгибание плеча с поддержкой не менее 120°',                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (1, 'passive_er_30_p1',        'Поворот руки наружу с поддержкой (рука у тела) не менее 30°',         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (1, 'passive_ir_0_p1',         'Поворот руки внутрь с поддержкой не менее 0° (без форсирования)',     'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (1, 'sleep_no_pain_wake_p1',   'Удаётся спать без частых пробуждений от боли',                        'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Удаётся спать без частых пробуждений от боли?', 'Оцените по нескольким последним ночам', 40::smallint, TRUE),
  (1, 'surgeon_healing_ok_p1',   'Хирург подтвердил заживление и соблюдение режима',                    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),
  (1, 'pain_controlled_rom_p1',  'Боль в разрешённом объёме движений под контролем',                   'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, TRUE),

  -- Фаза 2 → Фаза 3 (возврат активных движений → укрепление)
  (2, 'passive_flexion_140_p2',  'Сгибание плеча с поддержкой не менее 140°',                           'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 10::smallint, TRUE),
  (2, 'active_flexion_115_p2',   'Активное сгибание плеча не менее 115°',                               'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 20::smallint, TRUE),
  (2, 'full_passive_er_p2',      'Полный поворот руки наружу с поддержкой (рука у тела) — норма для пациента', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (2, 'pain_le_4_move_p2',       'Боль при движении не более 4 из 10',                                  'measurement',      'vas_score', 'pain', '<=', 4::numeric, NULL, 7::smallint, NULL, NULL, 40::smallint, TRUE),
  (2, 'no_scapular_hitch_p2',    'Нет компенсаторного подёргивания лопаткой при движении',             'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),
  (2, 'surgeon_strength_ok_p2',  'Хирург разрешил начинать укрепление',                                'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 60::smallint, TRUE),

  -- Фаза 3 → Фаза 4 (укрепление → возврат к спорту и труду)
  (3, 'er_ir_strength_85_p3',    'Сила наружного и внутреннего поворота плеча не менее 85% от здоровой руки', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 10::smallint, TRUE),
  (3, 'er_ir_ratio_60_p3',       'Соотношение силы наружных и внутренних вращателей плеча не менее 60%', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 30::smallint, NULL, NULL, 20::smallint, TRUE),
  (3, 'full_painless_rom_p3',    'Полный безболезненный объём движений плеча',                         'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 30::smallint, TRUE),
  (3, 'mmt_er_4_p3',             'Сила наружных вращателей плеча по мышечному тесту не ниже 4 из 5',    'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 40::smallint, TRUE),
  (3, 'tests_negative_p3',       'Тесты на ущемление и нестабильность отрицательные, лопатка работает симметрично', 'instructor_check', NULL, NULL, NULL, NULL, NULL, 14::smallint, NULL, NULL, 50::smallint, TRUE),
  (3, 'base_load_painless_p3',   'Базовые нагрузки и силовая программа безболезненны',                  'self_report',      NULL, NULL, NULL, NULL, NULL, 7::smallint, 'Безболезненны базовые нагрузки и силовая программа?', 'Оцените по нескольким последним тренировкам', 60::smallint, FALSE)
)
INSERT INTO phase_transition_criteria (
  phase_id, criterion_code, label, criterion_type,
  measurement_type, measurement_source,
  threshold_operator, threshold_value, threshold_value2, staleness_days,
  self_report_question, self_report_hint,
  position, is_required, is_active
)
SELECT
  p.id, cd.criterion_code, cd.label, cd.criterion_type,
  cd.measurement_type, cd.measurement_source,
  cd.threshold_operator, cd.threshold_value, cd.threshold_value2, cd.staleness_days,
  cd.self_report_question, cd.self_report_hint,
  cd.position, cd.is_required, TRUE
FROM criteria_data cd
JOIN rehab_phases p ON p.program_type = 'shoulder_rcr_infraspinatus' AND p.phase_number = cd.phase_number
ON CONFLICT (phase_id, criterion_code) DO NOTHING;

COMMIT;
